ctx.save();ctx.translate(cx,cy);ctx.rotate(roll*Math.PI/180);ctx.strokeStyle=C;ctx.lineWidth=2;ctx.globalAlpha=0.8;ctx.beginPath();ctx.moveTo(-40,0);ctx.lineTo(-14,0);ctx.stroke();ctx.beginPath();ctx.moveTo(14,0);ctx.lineTo(40,0);ctx.stroke();ctx.beginPath();ctx.arc(0,0,3,0,Math.PI*2);ctx.stroke();ctx.beginPath();ctx.moveTo(-40,0);ctx.lineTo(-40,6);ctx.stroke();ctx.beginPath();ctx.moveTo(40,0);ctx.lineTo(40,6);ctx.stroke();ctx.globalAlpha=1;ctx.restore();
