function startDOMWidgets(){mmDomCanvas=document.getElementById('minimapCanvas');mmDomCtx=mmDomCanvas.getContext('2d');var compCanvas=document.getElementById('compassCanvas'),compCtx=compCanvas.getContext('2d');var hrzCanvas=document.getElementById('horizonCanvas'),hrzCtx=hrzCanvas.getContext('2d');var edgeCanvas=document.getElementById('edgeArrowCanvas'),edgeCtx=edgeCanvas.getContext('2d');var headLbl=document.getElementById('mmHeadingLbl');function frame(){requestAnimationFrame(frame);if(xrSession)return;if(mapHeadingTarget!==null){if(mapHeading===null)mapHeading=mapHeadingTarget;var diff=mapHeadingTarget-mapHeading;if(diff>180)diff-=360;if(diff<-180)diff+=360;mapHeading=(mapHeading+diff*0.1+360)%360}mmDomCtx.clearRect(0,0,mmDomCanvas.width,mmDomCanvas.height);drawMinimap(mmDomCtx,mmDomCanvas.width/2,mmDomCanvas.height/2,MM_DOM_RADIUS);headLbl.textContent=mapHeadingRaw!==null?'HDG '+('00'+Math.round(mapHeading)).slice(-3)+'\u00B0':'HDG ---\u00B0';compCtx.clearRect(0,0,compCanvas.width,compCanvas.height);drawCompassTape(compCtx,0,0,compCanvas.width,22);hrzCtx.clearRect(0,0,hrzCanvas.width,hrzCanvas.height);drawArtificialHorizon(hrzCtx,hrzCanvas.width/2,hrzCanvas.height/2,hrzCanvas.width,hrzCanvas.height);var ew=window.innerWidth,eh=window.innerHeight;if(edgeCanvas.width!==ew||edgeCanvas.height!==eh){edgeCanvas.width=ew;edgeCanvas.height=eh}edgeCtx.clearRect(0,0,ew,eh);drawEdgeArrows(edgeCtx,ew,eh)}frame()}

function fetchThreat(){if(lat==null)return;document.getElementById('threatPanel').style.display='block';document.getElementById('threatSub').textContent='SCANNING...';var score=0,factors=[],done=0,needed=2;function tryFinish(){done++;if(done<needed)return;score=Math.min(10,Math.max(1,Math.round(score)));var col=score<=3?'#76ff03':score<=5?'#ffb300':score<=7?'#ff6d00':'#ff1744';var label=score<=3?'LOW':score<=5?'MODERATE':score<=7?'HIGH':'CRITICAL';var tv=document.getElementById('threatVal'),tb=document.getElementById('threatBar');tv.textContent=label+' '+score+'/10';tv.style.color=col;tb.style.width=(score/10*100)+'%';tb.style.background=col;tb.style.boxShadow='0 0 6px '+col;document.getElementById('threatSub').textContent=factors.slice(0,3).join(' \u00B7 ');if(score>=7)addAlert('THREAT: '+label,'danger');else if(score>=5)addAlert('THREAT: '+label,'warn')}setTimeout(function(){var envScore=0,wc=document.getElementById('wCond').textContent;var envMap={'STORM':3,'SNOW':2,'SHOWERS':1.5,'RAIN':1,'DRIZZLE':0.5,'FOG':1};envScore+=(envMap[wc]||0);var aqiEl=document.getElementById('wAqi');if(aqiEl&&aqiEl.textContent!=='--'){var aqi=parseInt(aqiEl.textContent)||0;if(aqi>80)envScore+=2;else if(aqi>60)envScore+=1.5;else if(aqi>40)envScore+=0.5}var hr=new Date().getHours();if(hr>=23||hr<5){envScore+=1.5;factors.push('NIGHT')}else if(hr<7||hr>=21)envScore+=0.5;if(wc!=='--'&&wc!=='CLEAR'&&wc!=='PARTLY CLOUDY')factors.push('WX:'+wc);score+=envScore;tryFinish()},100);fetch('https://data.police.uk/api/crimes-street/all-crime?lat='+lat+'&lng='+lon).then(function(r){if(!r.ok)throw new Error('not uk');return r.json()}).then(function(crimes){var count=Array.isArray(crimes)?crimes.length:0;score+=Math.min(4,count/12);if(count>0)factors.push(count+' CRIMES/MI');if(count>30)factors.push('HIGH CRIME');else if(count>15)factors.push('MOD CRIME');tryFinish()}).catch(function(){score+=(poiData.length>4?0.5:0);factors.push('NO CRIME DATA');tryFinish()})}
function addAlert(msg,type){alertsState.unshift({msg:msg,type:type});alertsState=alertsState.slice(0,4);var el=document.createElement('div');el.className='alert '+(type||'info');el.textContent=msg;document.getElementById('alerts').appendChild(el);setTimeout(function(){el.style.transition='opacity .3s';el.style.opacity='0';setTimeout(function(){el.remove()},300)},5000)}

