async function toggleCamZoom(){if(camZoomActive){camZoomActive=false;if(camZoomStream){camZoomStream.getTracks().forEach(function(t){t.stop()});camZoomStream=null}if(camZoomVideo){camZoomVideo.srcObject=null;camZoomVideo.remove();camZoomVideo=null}addAlert('CAM ZOOM OFF','info');return}try{camZoomStream=await navigator.mediaDevices.getUserMedia({video:{facingMode:{ideal:'environment'},width:{ideal:1920},height:{ideal:1080}}})}catch(e){addAlert('CAM DENIED','warn');return}camZoomVideo=document.createElement('video');camZoomVideo.setAttribute('autoplay','');camZoomVideo.setAttribute('playsinline','');camZoomVideo.setAttribute('muted','');camZoomVideo.muted=true;camZoomVideo.style.cssText='position:fixed;width:1px;height:1px;opacity:0;pointer-events:none';document.body.appendChild(camZoomVideo);camZoomVideo.srcObject=camZoomStream;var pr=camZoomVideo.play();if(pr&&pr.catch)pr.catch(function(){});camZoomActive=true;camZoomLevel=2.0;addAlert('CAM ZOOM '+camZoomLevel.toFixed(1)+'x','ok')}
